 58→// --- Named Mutex RAII wrapper ---
 59→struct WinMutex {
 60→    handle: HANDLE,
 61→}
 62→
 63→unsafe impl Send for WinMutex {}
 64→
 65→impl WinMutex {
 66→    fn try_acquire(name: &str) -> Option<Self> {
 67→        let wide: Vec<u16> = name.encode_utf16().chain(std::iter::once(0)).collect();
 68→        let handle = unsafe { CreateMutexW(std::ptr::null(), 0, wide.as_ptr()) };
 69→        if handle.is_null() {
 70→            return None;
 71→        }
 72→        // Always try to acquire ownership (matches C# mutex.WaitOne(0))
 73→        let wait = unsafe { WaitForSingleObject(handle, 0) };
 74→        if wait != WAIT_OBJECT_0 && wait != WAIT_ABANDONED {
 75→            unsafe { CloseHandle(handle) };
 76→            return None;
 77→        }
 78→        Some(WinMutex { handle })
 79→    }
 80→}
 81→
 82→impl Drop for WinMutex {
 83→    fn drop(&mut self) {
 84→        unsafe {
 85→            ReleaseMutex(self.handle);
 86→            CloseHandle(self.handle);
 87→        }
 88→    }
 89→}
