 91→// --- Command result ---
 92→struct CommandResult {
 93→    completed: bool,
 94→    timed_out: bool,
 95→    exit_code: Option<i32>,
 96→    stdout: String,
 97→    stderr: String,
 98→    error_message: String,
 99→}
