101→impl CommandResult {
102→    fn failed(message: String) -> Self {
103→        Self {
104→            completed: false,
105→            timed_out: false,
106→            exit_code: None,
107→            stdout: String::new(),
108→            stderr: String::new(),
109→            error_message: message,
110→        }
111→    }
112→
113→    fn timed_out_result(stdout: String, stderr: String) -> Self {
114→        Self {
115→            completed: false,
116→            timed_out: true,
117→            exit_code: None,
118→            stdout,
119→            stderr,
120→            error_message: String::new(),
121→        }
122→    }
123→
124→    fn completed_result(exit_code: i32, stdout: String, stderr: String) -> Self {
125→        Self {
126→            completed: true,
127→            timed_out: false,
128→            exit_code: Some(exit_code),
129→            stdout,
130→            stderr,
131→            error_message: String::new(),
132→        }
133→    }
134→}
