193→// --- Trim helper ---
194→fn trim_for_log(text: &str, max_length: usize) -> String {
195→    let trimmed = text.trim();
196→    if trimmed.is_empty() {
197→        return String::new();
198→    }
199→    let single_line: String = trimmed.replace(['\r', '\n'], " ");
200→    if single_line.len() <= max_length {
201→        single_line
202→    } else {
203→        let mut end = max_length;
204→        while !single_line.is_char_boundary(end) && end > 0 {
205→            end -= 1;
206→        }
207→        format!("{}...", &single_line[..end])
208→    }
209→}
