309→fn format_command_result(result: &CommandResult) -> String {
310→    let out_text = trim_for_log(&result.stdout, 160);
311→    let err_text = trim_for_log(&result.stderr, 160);
312→    let msg_text = trim_for_log(&result.error_message, 160);
313→    let exit_str = match result.exit_code {
314→        Some(code) => code.to_string(),
315→        None => "null".to_string(),
316→    };
317→    format!(
318→        "completed={}, timedOut={}, exitCode={}, stdout=\"{}\", stderr=\"{}\", error=\"{}\"",
319→        result.completed, result.timed_out, exit_str, out_text, err_text, msg_text
320→    )
321→}
