323→// --- Process management ---
324→fn is_espanso_process(process: &sysinfo::Process) -> bool {
325→    let name = process.name().to_string_lossy().to_lowercase();
326→    name == "espanso" || name == "espanso.exe" || name == "espansod" || name == "espansod.exe"
327→}
328→
329→fn get_espanso_process_count(sys: &mut System) -> usize {
330→    sys.refresh_processes(sysinfo::ProcessesToUpdate::All, true);
331→    sys.processes()
332→        .values()
333→        .filter(|p| is_espanso_process(p))
334→        .count()
335→}
336→
337→fn kill_espanso_processes(sys: &mut System) -> u32 {
338→    sys.refresh_processes(sysinfo::ProcessesToUpdate::All, true);
339→    let mut killed = 0u32;
340→    let pids: Vec<sysinfo::Pid> = sys
341→        .processes()
342→        .iter()
343→        .filter(|(_, p)| is_espanso_process(p))
344→        .map(|(pid, _)| *pid)
345→        .collect();
346→
347→    for pid in pids {
348→        if let Some(process) = sys.process(pid) {
349→            if process.kill() {
350→                killed += 1;
351→            } else {
352→                log(&format!("failed to kill pid={}", pid));
353→            }
354→        }
355→    }
356→    killed
357→}
358→
359→fn set_espanso_high_priority(sys: &mut System) -> u32 {
360→    sys.refresh_processes(sysinfo::ProcessesToUpdate::All, true);
361→    let mut count = 0u32;
362→    for (pid, process) in sys.processes() {
363→        if !is_espanso_process(process) {
364→            continue;
365→        }
366→        let raw_pid = pid.as_u32();
367→        let handle = unsafe { OpenProcess(PROCESS_SET_INFORMATION, 0, raw_pid) };
368→        if handle.is_null() {
369→            continue;
370→        }
371→        let ok = unsafe { SetPriorityClass(handle, HIGH_PRIORITY_CLASS) };
372→        unsafe { CloseHandle(handle) };
373→        if ok != 0 {
374→            count += 1;
375→        }
376→    }
377→    count
378→}
