380→// --- Espanso log analysis ---
381→fn read_tail_text(path: &PathBuf, max_bytes: u64) -> Result<String, std::io::Error> {
382→    let mut file = File::open(path)?;
383→    let length = file.metadata()?.len();
384→    let bytes_to_read = length.min(max_bytes);
385→    if bytes_to_read == 0 {
386→        return Ok(String::new());
387→    }
388→
389→    file.seek(SeekFrom::End(-(bytes_to_read as i64)))?;
390→    let mut buffer = vec![0u8; bytes_to_read as usize];
391→    let read = file.read(&mut buffer)?;
392→    let mut text = String::from_utf8_lossy(&buffer[..read]).to_string();
393→
394→    if length > max_bytes {
395→        if let Some(pos) = text.find('\n') {
396→            if pos + 1 < text.len() {
397→                text = text[pos + 1..].to_string();
398→            }
399→        }
400→    }
401→
402→    Ok(text)
403→}
404→
405→fn is_recent_espanso_log_line(line: &str) -> bool {
406→    if line.len() < 8 || !line.is_char_boundary(8) {
407→        return false;
408→    }
409→
410→    let time_str = &line[..8];
411→    let parsed_time = match NaiveTime::parse_from_str(time_str, "%H:%M:%S") {
412→        Ok(t) => t,
413→        Err(_) => return false,
414→    };
415→
416→    let now = Local::now();
417→    let today = now.date_naive();
418→    let mut line_dt = today
419→        .and_time(parsed_time)
420→        .and_local_timezone(Local)
421→        .single();
422→
423→    if let Some(dt) = line_dt {
424→        if dt > now + chrono::Duration::minutes(1) {
425→            line_dt = (today - chrono::Duration::days(1))
426→                .and_time(parsed_time)
427→                .and_local_timezone(Local)
428→                .single();
429→        }
430→    }
431→
432→    match line_dt {
433→        Some(dt) => {
434→            let diff = now.signed_duration_since(dt);
435→            diff >= chrono::Duration::zero()
436→                && diff <= chrono::Duration::minutes(CRITICAL_LOG_LOOKBACK_MINUTES)
437→        }
438→        None => false,
439→    }
440→}
441→
442→fn is_critical_espanso_log_line(line: &str) -> bool {
443→    let lower = line.to_lowercase();
444→    lower.contains("[error]")
445→        && lower.contains("could not restart worker")
446→        && is_recent_espanso_log_line(line)
447→}
448→
449→fn get_latest_critical_espanso_log_line() -> Option<String> {
450→    let path = espanso_log_path();
451→    if !path.exists() {
452→        return None;
453→    }
454→
455→    let tail = match read_tail_text(&path, ESPANSO_LOG_TAIL_BYTES) {
456→        Ok(t) => t,
457→        Err(e) => {
458→            log(&format!(
459→                "failed to read espanso.log: {}",
460→                trim_for_log(&e.to_string(), 200)
461→            ));
462→            return None;
463→        }
464→    };
465→
466→    let lines: Vec<&str> = tail.split(['\r', '\n']).filter(|l| !l.is_empty()).collect();
467→
468→    for line in lines.iter().rev() {
469→        if is_critical_espanso_log_line(line) {
470→            return Some(trim_for_log(line, 220));
471→        }
472→    }
473→
474→    None
475→}
