477→// --- Health check ---
478→struct HealthState {
479→    last_critical_log_line: Option<String>,
480→    sys: System,
481→    espanso_cli: String,
482→}
483→
484→impl HealthState {
485→    fn new() -> Self {
486→        Self {
487→            last_critical_log_line: None,
488→            sys: System::new(),
489→            espanso_cli: resolve_espanso_cli_path(),
490→        }
491→    }
492→
493→    fn is_healthy(&mut self) -> (bool, String) {
494→        let status_result = run_command(
495→            &self.espanso_cli,
496→            "service status",
497→            Duration::from_secs(STATUS_TIMEOUT_SECONDS),
498→        );
499→
500→        let service_running = status_result.completed
501→            && status_result
502→                .stdout
503→                .to_lowercase()
504→                .contains("espanso is running");
505→
506→        let process_count = get_espanso_process_count(&mut self.sys);
507→        let has_required = process_count >= EXPECTED_ESPANSO_PROCESS_COUNT;
508→        let basic_healthy = service_running && has_required;
509→
510→        if basic_healthy {
511→            if let Some(critical_line) = get_latest_critical_espanso_log_line() {
512→                let is_new = self.last_critical_log_line.as_ref() != Some(&critical_line);
513→                if is_new {
514→                    self.last_critical_log_line = Some(critical_line.clone());
515→                    let detail = format!(
516→                        "criticalEspansoError=\"{}\", serviceRunning={}, processCount={}, status={}",
517→                        critical_line,
518→                        service_running,
519→                        process_count,
520→                        format_command_result(&status_result)
521→                    );
522→                    return (false, detail);
523→                }
524→            }
525→        }
526→
527→        let detail = format!(
528→            "serviceRunning={}, processCount={}, status={}",
529→            service_running,
530→            process_count,
531→            format_command_result(&status_result)
532→        );
533→        (basic_healthy, detail)
534→    }
535→
536→    fn ensure_healthy(&mut self) -> bool {
537→        let (healthy, detail) = self.is_healthy();
538→        if healthy {
539→            let priority_count = set_espanso_high_priority(&mut self.sys);
540→            log(&format!(
541→                "healthy: {} (priority set on {} processes)",
542→                detail, priority_count
543→            ));
544→            return true;
545→        }
546→
547→        log(&format!("unhealthy detected: {}", detail));
548→
549→        for attempt in 1..=RECOVERY_RETRY_COUNT {
550→            let killed = kill_espanso_processes(&mut self.sys);
551→            log(&format!(
552→                "recovery attempt {}/{}: killed espanso processes={}.",
553→                attempt, RECOVERY_RETRY_COUNT, killed
554→            ));
555→
556→            thread::sleep(RECOVERY_KILL_WAIT);
557→
558→            let start_result = run_command(
559→                &self.espanso_cli,
560→                "service start --unmanaged",
561→                Duration::from_secs(START_TIMEOUT_SECONDS),
562→            );
563→
564→            log(&format!(
565→                "recovery attempt {}/{}: service start result={}.",
566→                attempt,
567→                RECOVERY_RETRY_COUNT,
568→                format_command_result(&start_result)
569→            ));
570→
571→            thread::sleep(RECOVERY_START_WAIT);
572→
573→            let (recovered, recovered_detail) = self.is_healthy();
574→            if recovered {
575→                let priority_count = set_espanso_high_priority(&mut self.sys);
576→                log(&format!(
577→                    "recovery succeeded on attempt {}: {} (priority set on {} processes)",
578→                    attempt, recovered_detail, priority_count
579→                ));
580→                return true;
581→            }
582→
583→            log(&format!(
584→                "recovery attempt {}/{} failed.",
585→                attempt, RECOVERY_RETRY_COUNT
586→            ));
587→        }
588→
589→        log("recovery failed after all retries.");
590→        false
591→    }
592→}
