594→// --- Entrypoint ---
595→fn main() {
596→    std::panic::set_hook(Box::new(|info| {
597→        let payload = if let Some(s) = info.payload().downcast_ref::<&str>() {
598→            s.to_string()
599→        } else if let Some(s) = info.payload().downcast_ref::<String>() {
600→            s.clone()
601→        } else {
602→            "unknown panic payload".to_string()
603→        };
604→        let location = info
605→            .location()
606→            .map(|l| format!("{}:{}:{}", l.file(), l.line(), l.column()))
607→            .unwrap_or_else(|| "unknown location".to_string());
608→        log(&format!("PANIC at {}: {}", location, payload));
609→    }));
610→
611→    let dir = app_dir();
612→    let _ = fs::create_dir_all(&dir);
613→
614→    let _mutex = match WinMutex::try_acquire(r"Local\EspansoWatchdogMutex") {
615→        Some(m) => m,
616→        None => {
617→            log("watchdog is already running. exiting.");
618→            return;
619→        }
620→    };
621→
622→    // Set own process to high priority
623→    unsafe {
624→        SetPriorityClass(GetCurrentProcess(), HIGH_PRIORITY_CLASS);
625→    }
626→
627→    let args: Vec<String> = env::args().collect();
628→    let run_once = args.iter().any(|a| a.eq_ignore_ascii_case("--once"));
629→
630→    if run_once {
631→        log("watchdog started in once mode.");
632→    } else {
633→        log("watchdog started in monitor mode.");
634→    }
635→
636→    let mut state = HealthState::new();
637→
638→    if run_once {
639→        let result = state.ensure_healthy();
640→        if result {
641→            log("once mode completed successfully.");
642→        } else {
643→            log("once mode failed to recover.");
644→            std::process::exit(1);
645→        }
646→        return;
647→    }
648→
649→    loop {
650→        match std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
651→            state.ensure_healthy();
652→        })) {
653→            Ok(_) => {}
654→            Err(_) => {
655→                log("recovered from panic in ensure_healthy, continuing monitoring.");
656→                thread::sleep(Duration::from_secs(MONITOR_INTERVAL_SECONDS * 3));
657→                continue;
658→            }
659→        }
660→        thread::sleep(Duration::from_secs(MONITOR_INTERVAL_SECONDS));
661→    }
662→}
