172→// --- Logging ---
173→fn log(message: &str) {
174→    let line = format!("{} {}", Local::now().format("%Y-%m-%d %H:%M:%S"), message);
175→    let _lock = LOG_LOCK.lock().unwrap_or_else(|e| e.into_inner());
176→
177→    let log = log_path();
178→
179→    // Log rotation
180→    if let Ok(meta) = fs::metadata(&log) {
181→        if meta.len() > MAX_LOG_FILE_BYTES {
182→            let backup = log.with_extension("log.old");
183→            let _ = fs::remove_file(&backup);
184→            let _ = fs::rename(&log, &backup);
185→        }
186→    }
187→
188→    if let Ok(mut f) = OpenOptions::new().create(true).append(true).open(&log) {
189→        let _ = writeln!(f, "{}", line);
190→    }
191→}
