211→// Kill a process and all its descendants (process tree).
212→fn kill_process_tree(pid: u32) {
213→    use std::os::windows::process::CommandExt;
214→    const CREATE_NO_WINDOW: u32 = 0x08000000;
215→    let _ = Command::new("taskkill")
216→        .args(["/F", "/T", "/PID", &pid.to_string()])
217→        .creation_flags(CREATE_NO_WINDOW)
218→        .stdout(std::process::Stdio::null())
219→        .stderr(std::process::Stdio::null())
220→        .status();
221→}
222→
223→// --- Run command with timeout ---
224→fn run_command(file_name: &str, arguments: &str, timeout: Duration) -> CommandResult {
225→    use std::os::windows::process::CommandExt;
226→    use std::sync::mpsc;
227→    const CREATE_NO_WINDOW: u32 = 0x08000000;
228→
229→    let args: Vec<&str> = arguments.split_whitespace().collect();
230→    let child = Command::new(file_name)
231→        .args(&args)
232→        .stdout(std::process::Stdio::piped())
233→        .stderr(std::process::Stdio::piped())
234→        .creation_flags(CREATE_NO_WINDOW)
235→        .spawn();
236→
237→    let mut child = match child {
238→        Ok(c) => c,
239→        Err(e) => return CommandResult::failed(e.to_string()),
240→    };
241→
242→    let child_pid = child.id();
243→
244→    // Read stdout/stderr in background threads to avoid pipe buffer deadlock.
245→    // Use channels so we can collect output with a timeout (child processes
246→    // may inherit pipe handles and keep them open after the parent exits).
247→    let (stdout_tx, stdout_rx) = mpsc::channel();
248→    let (stderr_tx, stderr_rx) = mpsc::channel();
249→
250→    if let Some(out) = child.stdout.take() {
251→        thread::spawn(move || {
252→            let mut s = String::new();
253→            let mut out = out;
254→            let _ = out.read_to_string(&mut s);
255→            let _ = stdout_tx.send(s);
256→        });
257→    }
258→    if let Some(err) = child.stderr.take() {
259→        thread::spawn(move || {
260→            let mut s = String::new();
261→            let mut err = err;
262→            let _ = err.read_to_string(&mut s);
263→            let _ = stderr_tx.send(s);
264→        });
265→    }
266→
267→    let start = std::time::Instant::now();
268→    loop {
269→        match child.try_wait() {
270→            Ok(Some(status)) => {
271→                // Process exited. Give reader threads 2s to finish
272→                // (child processes may keep pipes open longer).
273→                let stdout = stdout_rx
274→                    .recv_timeout(Duration::from_secs(2))
275→                    .unwrap_or_default();
276→                let stderr = stderr_rx
277→                    .recv_timeout(Duration::from_secs(2))
278→                    .unwrap_or_default();
279→                return CommandResult::completed_result(
280→                    status.code().unwrap_or(-1),
281→                    stdout.trim().to_string(),
282→                    stderr.trim().to_string(),
283→                );
284→            }
285→            Ok(None) => {
286→                if start.elapsed() >= timeout {
287→                    // Kill entire process tree so grandchildren that inherited
288→                    // pipe handles are also terminated, preventing thread leaks.
289→                    kill_process_tree(child_pid);
290→                    let _ = child.wait();
291→                    let stdout = stdout_rx
292→                        .recv_timeout(Duration::from_secs(2))
293→                        .unwrap_or_default();
294→                    let stderr = stderr_rx
295→                        .recv_timeout(Duration::from_secs(2))
296→                        .unwrap_or_default();
297→                    return CommandResult::timed_out_result(
298→                        stdout.trim().to_string(),
299→                        stderr.trim().to_string(),
300→                    );
301→                }
302→                thread::sleep(Duration::from_millis(100));
303→            }
304→            Err(e) => return CommandResult::failed(e.to_string()),
305→        }
306→    }
307→}
