# ============================================================
# パーサー: vscode-open.ahk をブロック単位で解析
# ============================================================
function Parse-Blocks {
    param([string[]]$Lines)

    $blocks = [System.Collections.Generic.List[hashtable]]::new()
    $pendingLines = [System.Collections.Generic.List[string]]::new()

    $i = 0
    # ヘルパー関数の終わりまでスキップ (最初の } 単独行)
    $passedHelper = $false
    while ($i -lt $Lines.Count) {
        if (-not $passedHelper) {
            if ($Lines[$i].Trim() -eq '}' -and $i -gt 5) {
                $passedHelper = $true
                $i++
                continue
            }
            $i++
            continue
        }

