        if ($line -match '^:\*::(.+?)::\s*\{') {
            $trigger = $Matches[1]
            $bodyLines = [System.Collections.Generic.List[string]]::new()
            $i++

            # } 単独行までボディを収集
            while ($i -lt $Lines.Count -and $Lines[$i].Trim() -ne '}') {
                $bodyLines.Add($Lines[$i])
                $i++
            }
            # } の行を消費
            $i++

            $blocks.Add(@{
                Type     = 'block'
                Trigger  = $trigger
                Body     = $bodyLines.ToArray()
                Before   = $pendingLines.ToArray()
            })
            $pendingLines.Clear()
            continue
        }

        # インライン hotstring: :*::trigger::replacement
        if ($line -match '^:\*::(.+?)::(.+)$') {
