    $out.Add('; ============================================================')
    $out.Add('')
    $out.Add('#Hotstring *')
    $out.Add('')
    $out.Add('; ============================================================')
    $out.Add('; ヘルパー関数')
    $out.Add('; ============================================================')
    $out.Add('')
    $out.Add('OpenPowerShell(path) {')
    $out.Add('    Run("powershell.exe", path)')
    $out.Add('}')

    foreach ($block in $blocks) {
        # trailing コメント
        if ($block.Type -eq 'trailing') {
            foreach ($l in $block.Lines) {
                $out.Add(($l -replace '; :esp は削除', '; :sesp は削除'))
            }
            continue
        }

        $trigger = $block.Trigger

        # 前置コメント (セクション区切り等)
        foreach ($l in $block.Before) {
            $out.Add(($l -replace '; :esp は削除', '; :sesp は削除'))
        }

        # 特殊ケース
        if ($SpecialBlocks.ContainsKey($trigger)) {
            $out.Add('')
            foreach ($sl in $SpecialBlocks[$trigger]) {
                $out.Add($sl)
            }
            continue
        }

        $newTrigger = "s$trigger"

        if ($block.Type -eq 'inline') {
            $replacement = $block.Replacement -replace 'OpenInVSCode\(', 'OpenPowerShell('
            $out.Add(":*::${newTrigger}::${replacement}")
        }
        else {
