            $out.Add(":*::${newTrigger}:: {")
            foreach ($bodyLine in $block.Body) {
                $out.Add(($bodyLine -replace 'OpenInVSCode\(', 'OpenPowerShell('))
            }
            $out.Add('}')
        }
    }

    $result = ($out -join "`n").TrimEnd() + "`n"
    [System.IO.File]::WriteAllText($TargetPath, $result, [System.Text.UTF8Encoding]::new($false))

    Write-Host "[$(Get-Date -Format 'yyyy-MM-dd HH:mm:ss')] Generated: $TargetPath"
}

# ============================================================
# メイン: 初回生成 + ファイル監視
# ============================================================
Build-PowershellOpen

$watcher = [System.IO.FileSystemWatcher]::new(
    [System.IO.Path]::GetDirectoryName($SourcePath),
    [System.IO.Path]::GetFileName($SourcePath)
)
$watcher.NotifyFilter = [System.IO.NotifyFilters]::LastWrite -bor [System.IO.NotifyFilters]::Size

Write-Host "[$(Get-Date -Format 'yyyy-MM-dd HH:mm:ss')] Watching: $SourcePath"

while ($true) {
    $result = $watcher.WaitForChanged([System.IO.WatcherChangeTypes]::Changed, 5000)
    if (-not $result.TimedOut) {
